  coaching_execution = '{"movement_description":"Walk along a line while holding a load in one hand and resisting side bend or foot drift.","setup":["Choose a light dumbbell or kettlebell.","Stand on a floor line with the load at one side.","Set tall posture and quiet shoulder position."],"execution_steps":["Walk slowly along the line without drifting off.","Keep ribs over pelvis and the load from pulling the torso sideways.","Turn around under control or switch hands at the end.","Repeat both sides."],"coach_cues":["Tall suitcase.","Do not lean away.","Feet find the line.","Shoulder quiet."],"athlete_cues":["Tall suitcase.","Do not lean away.","Feet find the line."],"breathing_cues":["Breathe quietly through the hold or reset.","Exhale during the hardest balance correction instead of holding the breath."],"common_faults":["Load too heavy and torso leans.","Feet step wide to compensate.","Grip fatigue changes posture.","Athlete rushes the walk."],"quality_gate":["Athlete walks the full distance with level shoulders, line foot placement, and no grip failure."],"stop_signs":["Back pain, grip failure, shoulder discomfort, or inability to keep the load controlled."]}'::jsonb,
