-- Half-Kneeling Get-Up to Stand (half-kneeling-get-up-to-stand)
UPDATE coaching.exercise SET
  name = 'Half-Kneeling Get-Up to Stand',
  description = 'Move from half-kneeling to standing and back down with strict foot pressure, hip control, and trunk organization.',
  card_summary = 'Half-Kneeling Get-Up to Stand is a balance-focused drill for teaches the athlete to move from ground to standing while keeping the center of mass over the base, a key wrestling and gymnastics transition skill. Use it when the goal is balance quality, body control, and repeatable recovery rather than fatigue.',
  coach_language = 'Primary subrole: trunk_pelvis_anti_movement_control. Coach Half-Kneeling Get-Up to Stand as balance skill plus control under the specific constraint: Teaches the athlete to move from ground to standing while keeping the center of mass over the base, a key wrestling and gymnastics transition skill. The set ends when posture, breath, foot pressure, or safe recovery breaks.',
  athlete_language = 'Stay centered, feel the floor, and recover your base before you fight the next force.',
  movement_family = 'Ground-to-stand balance',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
  primary_order_slot = 'perturbation_balance_control',
  default_sets = 2,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 40,
  est_seconds_per_set = 75,
  movement_requirements = '{"primary_joint_actions":["hip_transition_control","knee_extension","ankle_stability","shoulder_stabilization","spine_stabilization"],"primary_tissues":["glutes","quadriceps","obliques","shoulder_stabilizers"],"primary_motor_control_demands":["base_of_support_control","center_of_mass_management","postural_recovery","perturbation_response","anti_rotation_control"],"postural_shape":"athletic_or_wrestling_base_with_stacked_trunk","breathing_demand":"controlled_nasal_or_quiet_exhale","balance_demand":"external_perturbation_or_asymmetrical_load_balance","coordination_demand":"respond_to_external_force_without_losing_center_of_mass","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Move from half-kneeling to standing and back down with strict foot pressure, hip control, and trunk organization.","setup":["Start in a half-kneeling position on a mat.","Use bodyweight first; advanced athletes may hold a light load in a safe position.","Set front foot flat and torso tall."],"execution_steps":["Drive through the front foot to stand without pushing off the back foot excessively.","Pause in tall balance at the top.","Step back to the same half-kneeling position with control.","Repeat and switch sides."],"coach_cues":["Front foot owns the floor.","Stand through the hip.","Tall top position.","Return under control."],"athlete_cues":["Front foot owns the floor.","Stand through the hip.","Tall top position."],"breathing_cues":["Breathe quietly through the hold or reset.","Exhale during the hardest balance correction instead of holding the breath."],"common_faults":["Front knee collapses inward.","Athlete pushes off hands or back foot too much.","Torso twists during the stand.","Load is added before bodyweight control."],"quality_gate":["Athlete stands and returns to half-kneeling with no hand support, no knee collapse, and a held top position."],"stop_signs":["Knee pain, hip pinch, dizziness when standing, or unstable load control."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Sport-specific contact balance","Wrestling hand-fighting","Boundary reaction drill"],"pairs_well_after":["Half-Kneeling Narrow-Base Hold","Wrestler Stance Push-Pull Balance","Suitcase Carry Line Walk"],"good_for_sessions":["resilience","deceleration","court_field_balance"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or the athlete cannot maintain the required position.","Technique degrades before the set is complete.","The drill would be used as conditioning instead of balance-control practice.","Partner cannot keep contact predictable, controlled, and safe."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex demo recommended: Half-Kneeling Get-Up to Stand front and side views","Motor learning principle: low-fatigue, high-quality balance practice","NSCA-style landing, deceleration, and balance-control coaching reference"],"internal_notes":["Film from front or 45-degree angle when possible.","Approve progression only when foot pressure, knee tracking, pelvis, trunk, and breathing remain controlled.","Do not turn balance-control drills into conditioning races.","Balance cluster card; source: top_50_balance_exercise_library."]}'::jsonb,
  updated_at = now()
