INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'youth_intermediate', 'youth intermediate', 'baseline', v.guidance,
  CASE WHEN 'youth_intermediate' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
