);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops sideline, beam, and center-of-gravity balance qualities for athletic body control and contact recovery.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('single-leg-tripod-balance', 'Single-Leg Tripod Balance removes speed and fatigue so the athlete can feel the base of support, joint alignment, and breathing strategy. That creates a stable reference point before the same balance demand is challenged by motion, contact, or a narrower surface.', 'Belongs in Movement Intelligence because the main adaptation is learning and controlling balance positions while fresh, not accumulating fatigue. Slot: balance_control.', 'Use in Prepare & Access or early Movement Intelligence after temperature is raised. Keep it low fatigue so later sprint, skill, strength, or sport work stays sharp.', 'Do not make this a long boredom hold or use unstable gimmicks before the athlete owns simple floor balance. Stop when breathing, posture, or foot pressure degrades.', 'Scale one variable at a time: base width, visual input, range, speed, surface height, perturbation, external load, hold duration, or reset time. Progress only when the athlete can pause, breathe, and repeat the same alignment on both sides.'),
  ('tandem-line-balance-hold', 'Tandem Line Balance Hold removes speed and fatigue so the athlete can feel the base of support, joint alignment, and breathing strategy. That creates a stable reference point before the same balance demand is challenged by motion, contact, or a narrower surface.', 'Belongs in Movement Intelligence because the main adaptation is learning and controlling balance positions while fresh, not accumulating fatigue. Slot: balance_control.', 'Use in Prepare & Access or early Movement Intelligence after temperature is raised. Keep it low fatigue so later sprint, skill, strength, or sport work stays sharp.', 'Do not make this a long boredom hold or use unstable gimmicks before the athlete owns simple floor balance. Stop when breathing, posture, or foot pressure degrades.', 'Scale one variable at a time: base width, visual input, range, speed, surface height, perturbation, external load, hold duration, or reset time. Progress only when the athlete can pause, breathe, and repeat the same alignment on both sides.'),
